const body = $input.first().json.body || $input.first().json;
let campos = {};
if (body.entry && body.entry[0] && body.entry[0].changes) {
  const data = body.entry[0].changes[0].value;
  if (data.field_data) {
    data.field_data.forEach(f => { campos[f.name] = f.values[0]; });
  }
} else {
  campos = body;
}

const tipoEvento = campos['tipo_evento'] || campos['cual_es_tu_evento'] || campos['tipoEvento'] || 'No especificado';
const ev = tipoEvento.toLowerCase();
let segmento = 'Otro';
if (ev.includes('boda') || ev.includes('civil')) segmento = 'Bodas';
else if (ev.includes('xv') || ev.includes('quince')) segmento = 'XV Años';
else if (ev.includes('cumple') || ev.includes('infantil')) segmento = 'Cumpleaños';
else if (ev.includes('corporat') || ev.includes('empresa')) segmento = 'Corporativo';
else if (ev.includes('graduaci') || ev.includes('egresado')) segmento = 'Graduaciones';
else if (ev.includes('bautiz')) segmento = 'Bautizos';

const ahora = new Date();
const lead = {
  id: 'FB-' + ahora.getTime(),
  nombre: campos['full_name'] || campos['nombre'] || campos['name'] || 'Lead Facebook',
  email: campos['email'] || '',
  telefono: campos['phone_number'] || campos['telefono'] || campos['phone'] || '',
  evento: tipoEvento + ' (' + segmento + ')',
  fecha_evento: campos['fecha_del_evento'] || campos['event_date'] || campos['fecha'] || 'No especificada',
  personas: campos['cuantas_personas'] || campos['guests'] || campos['personas'] || 'No especificado',
  fuente: 'Facebook Lead Ad',
  status: 'nuevo',
  fecha_captura: ahora.toLocaleString('es-MX', { timeZone: 'America/Mexico_City' }),
  ultimo_email: ''
};
return [{ json: lead }];
